const now = new Date();
const pad = n => String(n).padStart(2, '0');
const timestamp = `${now.getFullYear()}${pad(now.getMonth()+1)}${pad(now.getDate())}_${pad(now.getHours())}${pad(now.getMinutes())}${pad(now.getSeconds())}`;

return [{
  json: {
    timestamp,
    backupFile: `/backups/ch_polarizados_backup_${timestamp}.sql.gz`,
    startedAt: now.toISOString()
  }
}];

const output = $input.first().json.stdout || '';
const lines = output.split('\n');
const result = {};

for (const line of lines) {
  if (line.startsWith('BACKUP_FILE=')) result.backupFile = line.split('=')[1];
  if (line.startsWith('BACKUP_SIZE=')) result.backupSize = line.split('=')[1];
  if (line.startsWith('TIMESTAMP=')) result.timestamp = line.split('=')[1];
}

result.success = !$input.first().json.stderr || $input.first().json.stderr.length === 0;
result.stdout = output;

return [{ json: result }];

// ✅ Backup exitoso - podés conectar aquí Telegram, email, Slack, etc.
// Descomentar y configurar según necesites

const { backupFile, backupSize, timestamp } = $input.first().json;
console.log(`✅ Backup OK: ${backupFile} (${backupSize})`);

return [{
  json: {
    message: `✅ Backup CH Polarizados completado`,
    file: backupFile,
    size: backupSize,
    timestamp
  }
}];

// ❌ Backup falló - notificar error
const { stdout } = $input.first().json;
console.error(`❌ Backup fallido: ${stdout}`);

return [{
  json: {
    message: `❌ Error en backup CH Polarizados`,
    error: stdout,
    timestamp: new Date().toISOString()
  }
}];
